  name: "get_stock_price",
  description: "Get current stock price for symbol.",
  input_schema: {
    type: "object",
    properties: {
      symbol: {
        type: "string",
        description: "Stock symbol (e.g., 'AAPL' for Apple). Use uppercase letters only."
      },
      exchange: {
        type: "string",
        description: "Optional exchange (e.g., 'NASDAQ'). If not provided, uses default."
      }
    },
    required: ["symbol"] // symbol is required, exchange is optional
  }
}

