// Schema guides Claude, but YOU validate
function executeTool(toolName, toolInput) {
  // Validate symbol is string
  if (typeof toolInput.symbol !== "string") {
    throw new Error("symbol must be a string");
  }
  // Validate symbol length (500 token limit per param)
  if (toolInput.symbol.length > 500) {
    throw new Error("symbol too long, exceeds parameter limit");
  }
  // Execute
  return getStockPrice(toolInput.symbol);
}

